insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('e4b4ecf1-58a0-5135-bc61-625934993a50','00000000-0000-0000-0000-00000000b001','vsp','Vinhomes Saigon Park','project','KĐT Đại học Quốc tế (VIUT) — Tây Bắc TP.HCM','[{"key":"Tên pháp lý","value":"Khu đô thị Đại học Quốc tế Việt Nam (VIUT)"},{"key":"Vị trí","value":"Xã Xuân Thới Sơn (Hóc Môn cũ) — GIÁP Quận 12"},{"key":"Quy mô","value":"~880 ha đất dự án (~1.080 ha tính cả sân golf)"},{"key":"Tổng vốn","value":"~59.000 tỷ đồng (~2,3–2,5 tỷ USD)"},{"key":"Quy mô dân số","value":"~135.000 cư dân + ~60.000 sinh viên"},{"key":"Khởi công","value":"29/4/2026 (VnExpress)"},{"key":"Tiến độ dự án","value":"120 tháng (QĐ 80/QĐ-TTg)"}]'::jsonb,'"Vinhomes không nằm trong Quận 12 — nhưng 880 ha của Vinhomes đặt sát vách Quận 12. Lịch sử Vinhomes Grand Park cho thấy: khu vực quanh đại đô thị Vin luôn được kéo mặt bằng giá lên trước cả khi dự án bàn giao."','✅ ĐÃ XÁC MINH (VnExpress, CafeF, VietnamBiz, văn bản quy hoạch) Vinhomes Saigon Park là tên thương mại của Khu đô thị Đại học Quốc tế Việt Nam (VIUT) — đại đô thị ~880 ha tại xã Xuân Thới Sơn (Hóc Môn cũ), khu Tây Bắc TP.HCM, do Vingroup/Vinhomes phát triển, vốn ~59.000 tỷ đồng. Khởi công 29/4/2026. Điểm cần nói rõ với khách: dự án KHÔNG nằm trong ranh Quận 12 — nó nằm GIÁP phía Tây Bắc Quận 12, mặt tiền Quốc lộ 22 và Vành đai 3. Quận 12 hưởng lợi gián tiếp về hạ tầng và mặt bằng giá.',0),
  ('76e34285-1178-556e-bc1b-a90fc5c6d436','00000000-0000-0000-0000-00000000b001','vsp-gd1','Giai đoạn 1 (~55 ha)','project',null,'[{"key":"Phạm vi","value":"~55 ha phía Nam dự án"},{"key":"Sản phẩm dự kiến","value":"~2.000 căn hộ + 255 nhà liền kề"},{"key":"Giao đất","value":"QĐ 1426/QĐ-UBND ngày 12/3/2026"},{"key":"Mở bán dự kiến","value":"Giữa 2026"}]'::jsonb,'"Giai đoạn 1 đã có quyết định giao đất — đây là mốc pháp lý thật, không phải tin đồn. Cái chưa có là bảng giá. Ai nói với Anh/Chị đã có giá chính thức thì đang nói trước CĐT."','◐ XÁC MINH MỘT PHẦN Giai đoạn 1 đã được giao đất chính thức (QĐ 1426/QĐ-UBND, 12/3/2026) — pháp lý nền cho đợt sản phẩm đầu tiên. Cơ cấu ~2.000 căn hộ + 255 nhà liền kề và mốc mở bán giữa 2026 là thông tin thị trường, chưa có công bố bán hàng chính thức từ CĐT.',1),
  ('72d9a0a3-d083-575e-951e-bc6c182b42e9','00000000-0000-0000-0000-00000000b001','vsp-products','Cơ cấu sản phẩm (QH 1/500)','project',null,'[{"key":"Biệt thự","value":"552 căn (tối đa 4 tầng)"},{"key":"Nhà liền kề","value":"2.491 căn (tối đa 5 tầng)"},{"key":"Nhà tái định cư","value":"815 căn"},{"key":"Chung cư","value":"Cao 12–22 tầng"},{"key":"Nhà ở xã hội","value":"3–10 tầng"},{"key":"Đất ở","value":"436 ha"},{"key":"DV – nghiên cứu – giáo dục","value":"150 ha"},{"key":"Cây xanh – mặt nước","value":"117 ha"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (hồ sơ quy hoạch chi tiết 1/500 được duyệt) Cơ cấu thấp tầng theo quy hoạch chính thức: 552 biệt thự + 2.491 liền kề + 815 tái định cư; cao tầng 12–22 tầng; nhà ở xã hội 3–10 tầng. Tỷ trọng cây xanh – mặt nước 117 ha + cụm giáo dục 150 ha là khung "đại học quốc tế" của dự án. Lưu ý: các con số khác (18.443 căn thấp tầng, 60 tòa tháp…) lan truyền trên web môi giới không khớp với hồ sơ quy hoạch — xem node "Phân khu rumor".',2),
  ('a38ac995-6a07-5b59-a090-ebc93a61d222','00000000-0000-0000-0000-00000000b001','vsp-gia-rumor','Giá & chính sách (rumor)','project','⚠ TIN ĐỒN — CĐT chưa công bố','[{"key":"Nhà phố (rumor)","value":"80–120 triệu/m² (chưa VAT)"},{"key":"Biệt thự (rumor)","value":"100–180 triệu/m² (chưa VAT)"},{"key":"CS bán hàng (đồn)","value":"HTLS 0–6%/năm cố định 5 năm"},{"key":"Ân hạn gốc (đồn)","value":"24–60 tháng"}]'::jsonb,'"Con số 80–120 triệu/m² là giá môi giới truyền tai — chưa có một văn bản nào từ Vinhomes. Quy tắc an toàn: không xuống tiền giữ chỗ dựa trên giá rumor."','⚠ TIN ĐỒN / CHƯA XÁC MINH Toàn bộ con số giá hiện lưu hành đến từ môi giới và website không chính thức. Vingroup/Vinhomes CHƯA công bố bảng giá hay chính sách bán hàng cho dự án này. Mức rumor 80–120 triệu/m² nhà phố là rất cao so với mặt bằng Quận 12 hiện tại (nhà phố 40–134 triệu/m² tùy vị trí).',3),
  ('c967fa18-f7a2-5b5c-b520-612cb8b304f3','00000000-0000-0000-0000-00000000b001','vsp-phankhu-rumor','Phân khu chủ đề (rumor)','project','⚠ CHƯA XÁC MINH — nguồn web môi giới','[{"key":"Tên phân khu (đồn)","value":"Ivy Park, Global Park, Laguna Park, Zen Park…"},{"key":"Số tháp (đồn)","value":"\"60 tòa tháp căn hộ\""},{"key":"Thấp tầng (đồn)","value":"\"18.443 căn\" — mâu thuẫn QH 1/500"},{"key":"Sân golf (đồn)","value":"\"Vinpearl Léman 200 ha\""}]'::jsonb,null,'⚠ TIN ĐỒN / CHƯA XÁC MINH Các thông tin "5–9 phân khu chủ đề", "60 tòa tháp", "18.443 căn thấp tầng" chỉ xuất hiện trên website môi giới (vinhome.com.vn, adongland.vn, vinhomesaigonpark.com…), không có trong văn bản quy hoạch được báo chí chính thống dẫn lại. Riêng con số thấp tầng mâu thuẫn trực tiếp với QH 1/500 (552 BT + 2.491 LK + 815 TĐC). Dùng để tham khảo không khí thị trường, không dùng làm căn cứ tư vấn.',4),
  ('f409ab45-f35c-5011-9930-074ee5f62e10','00000000-0000-0000-0000-00000000b001','vinhomes','Vinhomes (VHM)','developer',null,'[{"key":"Vai trò","value":"Nhà phát triển thương hiệu dự án"},{"key":"Sở hữu pháp nhân","value":"~97,9% CTCP Berjaya VN"},{"key":"Mốc 29/5/2026","value":"Công bố hoàn tất nhận chuyển nhượng cổ phần → công ty con"},{"key":"Track record","value":"Ocean Park, Grand Park, Smart City…"}]'::jsonb,'"Mô hình lặp lại: Grand Park kéo giá cả khu Long Bình – Long Thạnh Mỹ lên gấp nhiều lần. Câu hỏi không phải Vinhomes có làm được không, mà là khu vực quanh dự án đã phản ánh kỳ vọng đó vào giá chưa."','✅ ĐÃ XÁC MINH (công bố thông tin bất thường VHM 29/5/2026 — CafeF/MarketTimes) Vinhomes là nhà phát triển BĐS nhà ở số 1 Việt Nam. Ngày 29/5/2026, Vinhomes công bố đã nhận chuyển nhượng cổ phần tại CTCP Đô thị Đại học Quốc tế Berjaya Việt Nam, đưa pháp nhân dự án trở thành công ty con — hoàn tất chuỗi sở hữu cho Vinhomes Saigon Park.',5),
  ('104192a3-ff8b-5e81-b44d-8c9d07df9667','00000000-0000-0000-0000-00000000b001','vingroup','Vingroup','developer',null,'[{"key":"M&A 2/2018","value":"Mua lại dự án từ Berjaya (Malaysia)"},{"key":"Giá trị thương vụ","value":"11.748 tỷ đồng ≈ 97,9% vốn điều lệ"},{"key":"Đánh giá","value":"Một trong các M&A BĐS lớn nhất 2018 (VietnamBiz)"}]'::jsonb,'"Dự án này không mới — nó được cấp phép từ 2008 dưới tên Berjaya và bất động 10 năm. Điểm thay đổi cuộc chơi là Vingroup vào năm 2018 và pháp lý chạy thật từ 2025–2026."','✅ ĐÃ XÁC MINH (VietnamBiz) Vingroup mua lại dự án VIUT từ tập đoàn Berjaya (Malaysia) hồi tháng 2/2018 với giá 11.748 tỷ đồng (~97,9% vốn điều lệ pháp nhân dự án) — dự án "đắp chiếu" từ 2008 được hồi sinh dưới thương hiệu Vinhomes sau 8 năm Vingroup nắm giữ.',6),
  ('805ee670-1060-58de-9201-be9342e55f31','00000000-0000-0000-0000-00000000b001','berjaya-vn','CTCP ĐT ĐH Quốc tế Berjaya VN','developer','Pháp nhân dự án','[{"key":"Vai trò","value":"Pháp nhân trực tiếp của dự án VIUT"},{"key":"Nguồn gốc","value":"Berjaya Land (Malaysia), cấp phép 2008"},{"key":"Hiện tại","value":"Công ty con của Vinhomes (~97,9%)"}]'::jsonb,'"Khi khách tra cứu pháp lý thấy tên ''Berjaya'' thay vì ''Vinhomes'' — đó không phải red flag, đó là pháp nhân lịch sử của dự án mà Vinhomes sở hữu ~97,9%."','✅ ĐÃ XÁC MINH Pháp nhân đứng tên dự án là Công ty CP Đô thị Đại học Quốc tế Berjaya Việt Nam — tên còn giữ dấu vết chủ cũ Berjaya. Mọi văn bản pháp lý (QĐ 80, QĐ 273, QĐ 1426) đều cấp cho pháp nhân này, nay là công ty con của Vinhomes.',7),
  ('c73a03c3-6e95-5202-ac90-cf17fc61ffef','00000000-0000-0000-0000-00000000b001','qd-80','QĐ 80/QĐ-TTg (13/1/2025)','legal',null,'[{"key":"Cấp","value":"Thủ tướng Chính phủ"},{"key":"Nội dung","value":"Điều chỉnh chủ trương đầu tư VIUT"},{"key":"Tiến độ cho phép","value":"120 tháng"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Quyết định 80/QĐ-TTg ngày 13/1/2025 điều chỉnh chủ trương đầu tư Khu đô thị Đại học Quốc tế — văn bản "mở khóa" để dự án chạy lại sau nhiều năm đình trệ, cho phép tiến độ thực hiện 120 tháng.',8),
  ('e658472d-a36a-5283-bc2f-89781bc10cfd','00000000-0000-0000-0000-00000000b001','qh-1500','QH 1/500 — QĐ 273 (31/1/2026)','legal',null,'[{"key":"QĐ 273/QĐ-UBND","value":"31/1/2026 — duyệt quy hoạch chi tiết 1/500"},{"key":"Trước đó","value":"Duyệt nhiệm vụ QH phân khu 1/2000 (12/2025)"}]'::jsonb,'"1/500 đã duyệt là khác biệt căn bản so với 90% ''dự án tin đồn'' khác ở vùng ven — đây là dự án có quy hoạch chi tiết thật, đóng dấu thật."','✅ ĐÃ XÁC MINH Quy hoạch chi tiết 1/500 được duyệt ngày 31/1/2026 — căn cứ pháp lý cho cơ cấu sản phẩm (552 BT, 2.491 LK, 815 TĐC, chung cư 12–22 tầng). Mọi con số sản phẩm ngoài văn bản này đều thuộc nhóm rumor.',9),
  ('0cbb6e5d-f680-5e68-a0cd-b880a3cdbadd','00000000-0000-0000-0000-00000000b001','giao-dat','Giao đất GĐ1 — QĐ 1426 (12/3/2026)','legal',null,'[{"key":"QĐ 1426/QĐ-UBND","value":"12/3/2026"},{"key":"Phạm vi","value":"Giao đất giai đoạn 1 (~55 ha phía Nam)"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Quyết định giao đất giai đoạn 1 — bước pháp lý ngay trước khởi công. Chuỗi văn bản QĐ 80 → 1/2000 → 1/500 → giao đất hoàn chỉnh trong ~14 tháng cho thấy dự án được ưu tiên xử lý thủ tục.',10),
  ('affdb3d0-28c7-5c45-a4b3-dd1c0b7990f8','00000000-0000-0000-0000-00000000b001','khoi-cong','Khởi công 29/4/2026','legal',null,'[{"key":"Ngày chính thức","value":"29/4/2026 (VnExpress) — dịp 51 năm thống nhất"},{"key":"⚠ Phân biệt","value":"Cùng ngày khởi công Metro 2 đoạn Bến Thành–Thủ Thiêm"},{"key":"⚠ Tin sai phổ biến","value":"Một số web môi giới ghi 19/12/2025 — KHÔNG đúng"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (VnExpress: KĐT Đại học Quốc tế 880 ha khởi công 29/4) Hai sự kiện trùng ngày 29/4/2026 dễ gây nhầm trong tư vấn: (1) khởi công Vinhomes Saigon Park; (2) khởi công Metro số 2 đoạn nối dài Bến Thành – Thủ Thiêm. Ngày 19/12/2025 lan truyền trên web môi giới là thông tin sai.',11),
  ('ccad5f02-0f8b-5863-a043-4c6f296148a5','00000000-0000-0000-0000-00000000b001','ten-phap-ly','Giải mã tên gọi','legal',null,'[{"key":"Tên pháp lý","value":"Khu đô thị Đại học Quốc tế VN (VIUT)"},{"key":"Tên thương mại","value":"Vinhomes Saigon Park"},{"key":"\"Vinhomes Quận 12\"","value":"KHÔNG tồn tại — chỉ là cách gọi thị trường"},{"key":"\"Vinhomes Wonder City\"","value":"Dự án ở Đan Phượng, HÀ NỘI — không liên quan"}]'::jsonb,'"Câu khách hỏi nhiều nhất: ''Vinhomes có ở Quận 12 không?'' — Trả lời chuẩn: Không nằm trong, nằm sát vách. Và chính vì sát vách nên Quận 12 là vùng hưởng lợi giá hợp lý hơn so với mua trực tiếp trong dự án."','✅ ĐÃ XÁC MINH Không có dự án Vinhomes nào nằm trong địa giới Quận 12. Khi thị trường nói "Vinhomes Quận 12" tức là nói Vinhomes Saigon Park ở Xuân Thới Sơn (Hóc Môn cũ), giáp ranh Quận 12. "Vinhomes Wonder City" là dự án Hà Nội — môi giới ghép tên này vào TP.HCM là sai.',12),
  ('1f739c48-1983-56ea-80d6-f202738fc299','00000000-0000-0000-0000-00000000b001','metro-2','Metro số 2 (Bến Thành–Tham Lương)','metro',null,'[{"key":"Chiều dài","value":"11,3 km — 10 ga"},{"key":"Tổng mức đầu tư","value":"55.179 tỷ (QĐ 3639, 31/12/2025)"},{"key":"Tổng thầu EPC","value":"THACO (Trường Hải)"},{"key":"Khởi công","value":"15/1/2026 tại Depot Tham Lương"},{"key":"Mục tiêu vận hành","value":"Quý IV/2030 (57 tháng thi công)"},{"key":"Công nghệ","value":"GoA4 tự động không người lái, 80–110 km/h"},{"key":"GPMB","value":"100% hoàn thành (MAUR, 1/2026)"}]'::jsonb,'"Khác biệt 2026 so với 10 năm tin đồn metro trước đây: lần này máy đã chạy, GPMB xong 100%, và tổng thầu là THACO — doanh nghiệp Việt có áp lực tiến độ chính trị rất lớn."','✅ ĐÃ XÁC MINH (VTV, VnExpress, Dân trí 14/1/2026) Catalyst hạ tầng lớn nhất của Quận 12: tuyến metro nối thẳng Quận 12 (Depot Tham Lương) về Bến Thành. Đã khởi công thật 15/1/2026, GPMB xong 100%, tổng thầu nội địa THACO. Năng lực thiết kế ~14.418 hành khách/giờ/hướng. Lưu ý rủi ro: tuyến này từng trễ ~14 năm ở các giai đoạn trước — mốc Q4/2030 cần theo dõi tiến độ xây lắp thực tế.',13),
  ('125cf849-28d4-5465-add3-0ec86fce008d','00000000-0000-0000-0000-00000000b001','depot-tham-luong','Depot Tham Lương (Q12)','metro',null,'[{"key":"Vị trí","value":"Phường Trung Mỹ Tây (Tân Chánh Hiệp cũ), Quận 12"},{"key":"Vai trò","value":"Điểm cuối tuyến + nơi khởi công 15/1/2026"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Depot Tham Lương đặt ngay trong Quận 12 — nghĩa là Quận 12 không chỉ "gần metro" mà là điểm cuối vận hành của tuyến số 2. BĐS bán kính 1–2 km quanh depot/ga cuối thường là vùng hưởng lợi giá rõ nhất khi tuyến vận hành.',14),
  ('2a7f5c85-58cf-52ed-a1c9-d0a107e716d9','00000000-0000-0000-0000-00000000b001','metro-4','Metro số 4 (Thạnh Xuân–Hiệp Phước)','metro','Giai đoạn nghiên cứu — chưa khởi công','[{"key":"Chiều dài","value":"~36,2 km"},{"key":"Depot 1","value":"Thạnh Xuân, Quận 12 (~25–27 ha)"},{"key":"Nhà đầu tư quan tâm","value":"Sovico (đã ký MOU)"},{"key":"Khởi công","value":"Dự kiến sau Q2/2026"},{"key":"Mục tiêu hoàn thành","value":"~2035"}]'::jsonb,'"Metro 4 là tin tốt để kể, không phải tin tốt để định giá. Định giá hôm nay chỉ nên tính Metro 2 và Vành đai 3 — những thứ đang thi công thật."','◐ XÁC MINH MỘT PHẦN — quy hoạch depot tại Thạnh Xuân là thật, nhưng dự án còn ở giai đoạn nghiên cứu khả thi/kêu gọi đầu tư. Tuyến trục Bắc–Nam đi qua Thạnh Xuân (P. Thới An mới) xuống Hiệp Phước. Với nhà đầu tư, đây là câu chuyện 2030+ — không nên trả giá hiện tại cho catalyst này.',15),
  ('c903da89-bc32-5a6a-a7be-b856997e5aa0','00000000-0000-0000-0000-00000000b001','vd3','Vành đai 3 TP.HCM','road',null,'[{"key":"Quy mô","value":"76 km (đoạn TP.HCM 47,5 km)"},{"key":"Khởi công","value":"6/2023"},{"key":"Đoạn HM–CC–BC (32,6 km)","value":"Thông xe kỹ thuật dự kiến 30/4/2026"},{"key":"Toàn đoạn TP.HCM","value":"Mục tiêu trước 30/6/2026"},{"key":"⚠ Cảnh báo","value":"Có thể lùi cuối 2026 (nền đất yếu — Tuổi Trẻ)"}]'::jsonb,'"Theo dõi một mốc duy nhất: xe có chạy thật trên Vành đai 3 đoạn Hóc Môn trước 30/6/2026 không. Nếu có — kịch bản giá tích cực. Nếu lùi — đừng fomo theo tin ''sắp thông xe''."','✅ ĐÃ XÁC MINH (Tuổi Trẻ, Ban Giao thông) Vành đai 3 chạy sát Vinhomes Saigon Park và là trục kết nối liên vùng quan trọng nhất khu Tây Bắc. Đoạn qua Hóc Môn – Củ Chi – Bình Chánh dự kiến thông xe kỹ thuật 30/4/2026, nhưng Ban Giao thông đã cảnh báo nguy cơ lùi đến cuối 2026 (đoạn Củ Chi cũ đến 30/9/2026) do xử lý nền đất yếu.',16),
  ('b4dddc35-9f7f-5e40-8384-c7cdea07f6a2','00000000-0000-0000-0000-00000000b001','ql22','Mở rộng Quốc lộ 22','road',null,'[{"key":"Đoạn","value":"An Sương → Vành đai 3 (~8–9 km)"},{"key":"Quy mô","value":"Rộng 60 m / 10 làn xe, 7 cầu vượt"},{"key":"Vốn","value":"10.424 tỷ — hình thức BOT"},{"key":"Khởi công","value":"Dự kiến Q2–Q3/2026"},{"key":"Hoàn thành","value":"Mục tiêu 2028"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (Tuổi Trẻ, Báo Đầu tư) QL22 là mặt tiền của Vinhomes Saigon Park và là trục xương sống nối Quận 12 (nút An Sương) lên Tây Bắc. Mở rộng lên 10 làn trực tiếp giải bài toán "đường nhỏ – dự án to" của khu vực.',17),
  ('d0c9bb94-079f-5623-8015-129e53c3d973','00000000-0000-0000-0000-00000000b001','vd2','Vành đai 2','road',null,'[{"key":"Liên quan Q12","value":"Tuyến đi qua địa bàn Quận 12"},{"key":"Đoạn 1–2 (phía Đông)","value":"Khởi công 19/12/2025, mục tiêu 2027"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Vành đai 2 đi qua Quận 12 (trục QL1A hiện hữu); các đoạn còn thiếu chủ yếu ở phía Đông (Thủ Đức) đã khởi công 19/12/2025. Với Quận 12, giá trị chính là giảm tải QL1A khi khép kín vành đai.',18),
  ('3809d70a-cd02-5fa8-8d20-82ddb44feb7f','00000000-0000-0000-0000-00000000b001','nga-tu-dinh','Cầu vượt Ngã Tư Đình','road',null,'[{"key":"Vị trí","value":"QL1 × Nguyễn Văn Quá, Quận 12"},{"key":"Khởi công","value":"19/8/2025"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Nút giao Ngã Tư Đình là một trong các điểm kẹt xe nặng nhất Quận 12. Cầu vượt khởi công 19/8/2025 — catalyst nhỏ nhưng tác động trực tiếp đến trải nghiệm sống khu Đông Hưng Thuận / Trung Mỹ Tây.',19),
  ('112d3f21-2a72-5efc-96eb-03057fe81eec','00000000-0000-0000-0000-00000000b001','truc-q12','Trục nội khu Q12','road',null,'[{"key":"Các trục chính","value":"Hà Huy Giáp, Lê Văn Khương, Tô Ký, QL1A/Trường Chinh"},{"key":"Hiện trạng","value":"Quá tải giờ cao điểm — điểm trừ lớn nhất của Q12"}]'::jsonb,'"Đừng né câu hỏi kẹt xe — hãy lật nó: chính vì kẹt xe mà giá Q12 đang rẻ hơn Gò Vấp 30–40%. Mua bây giờ là mua cái bất tiện hôm nay để lấy hạ tầng ngày mai."','✅ ĐÃ XÁC MINH (hiện trạng phổ biến, được phản ánh thường xuyên trên báo chí) Hạ tầng nội khu là gót chân Achilles của Quận 12: các trục Hà Huy Giáp, Lê Văn Khương, Tô Ký thường xuyên ùn tắc. Đây vừa là lý do giá Q12 còn "trũng", vừa là upside khi các dự án mở rộng/metro hoàn thành.',20),
  ('f642eb24-87f4-5322-ba20-1ed1da2a09d8','00000000-0000-0000-0000-00000000b001','qtsc','Công viên phần mềm Quang Trung','amenity',null,'[{"key":"Vị trí","value":"Quận 12 (khu Tân Chánh Hiệp/Đông Hưng Thuận)"},{"key":"Vai trò","value":"Hub IT — nguồn cầu thuê nhân sự công nghệ"}]'::jsonb,null,'✅ ĐÃ XÁC MINH QTSC là công viên phần mềm lớn nhất Việt Nam, nằm ngay trong Quận 12 — nguồn cầu thuê ổn định cho căn hộ khu Trung Mỹ Tây / Tân Thới Hiệp với tệp khách nhân viên IT thu nhập khá.',21),
  ('41ed345f-5ede-5d89-9548-f2df3bc1150e','00000000-0000-0000-0000-00000000b001','kcn','Cụm KCN lân cận','amenity',null,'[{"key":"Các KCN","value":"Tân Bình, Vĩnh Lộc, Tân Phú Trung"},{"key":"Tác động","value":"Tạo cầu thuê + cầu mua ở thực bền vững"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Vành đai KCN quanh Quận 12 tạo nền cầu thuê thật (công nhân kỹ thuật, quản lý cấp trung) — lý do tỷ lệ lấp đầy cho thuê căn hộ Q12 ổn định dù giá thuê không cao.',22),
  ('7f36b434-59bc-5e75-8aa2-c8af93083c40','00000000-0000-0000-0000-00000000b001','song-sg','Sông Sài Gòn','amenity',null,'[{"key":"Liên quan Q12","value":"Giáp toàn bộ ranh phía Đông (An Phú Đông/Thạnh Lộc cũ)"},{"key":"Tiềm năng","value":"Quỹ đất ven sông + quy hoạch đường ven sông"},{"key":"⚠ Rủi ro","value":"Nền đất yếu, ngập cục bộ một số khu vực"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN Mặt tiền sông Sài Gòn phía Đông là tài sản dài hạn của Quận 12 (P. An Phú Đông mới). Nhưng cần tư vấn trung thực: một phần khu vực ven sông nền đất yếu và có ngập cục bộ — chi phí xây dựng cao hơn và cần kiểm tra cốt nền từng vị trí.',23),
  ('04433a4b-af09-511a-bd23-fa89a710df74','00000000-0000-0000-0000-00000000b001','vin-utilities','Hệ tiện ích Vin (tương lai)','amenity','Theo mô hình Vinhomes — chờ công bố chi tiết','[{"key":"Giáo dục","value":"Vinschool + cụm đại học quốc tế (~60.000 SV)"},{"key":"Y tế","value":"Vinmec (theo mô hình chuẩn Vinhomes)"},{"key":"Thương mại","value":"Vincom Mega Mall (kỳ vọng thị trường)"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — cụm giáo dục 150 ha có trong quy hoạch; tên thương hiệu tiện ích cụ thể (Vinschool/Vinmec/Vincom) là suy đoán theo mô hình chuẩn Vinhomes, chưa có công bố riêng cho dự án này. Nếu vận hành đúng mô hình, đây là cú hích tiện ích lớn nhất lịch sử khu Tây Bắc — vùng hiện không có trung tâm thương mại quy mô lớn nào.',24),
  ('81e2a746-b327-5dd2-82d3-46308d906454','00000000-0000-0000-0000-00000000b001','quan-12','Quận 12 (khu vực)','location',null,'[{"key":"Hành chính từ 1/7/2025","value":"Còn 5 phường, bỏ cấp quận (chỉ còn là tên khu vực)"},{"key":"Khoảng cách","value":"~10 km tới Tân Sơn Nhất, ~15 km tới Quận 1"},{"key":"Đặc điểm","value":"Vùng trũng giá phía Tây Bắc, giáp sông Sài Gòn"},{"key":"Nguồn cung căn hộ mới","value":"Khan hiếm — dự án mới nhất bàn giao 2022"}]'::jsonb,'"Công thức Quận 12 cho khách: giá Dĩ An – Thuận An của 5 năm trước + Metro đang xây + Vinhomes sát bên. Đó là setup từng xảy ra ở khu Đông trước khi giá gấp đôi."','✅ ĐÃ XÁC MINH Quận 12 sau 1/7/2025 không còn là đơn vị hành chính (TP.HCM bỏ cấp quận) — nhưng vẫn là tên khu vực thông dụng. Vị thế đầu tư: vùng trũng giá có 2 catalyst thi công thật (Metro 2, VĐ3) + 1 đại đô thị Vinhomes sát vách.',25),
  ('1b04684a-016b-5bdf-bdef-f49a794e2b60','00000000-0000-0000-0000-00000000b001','p-thoi-an','P. Thới An (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Thới An + Thạnh Xuân"},{"key":"Trụ sở","value":"340 Lê Văn Khương"},{"key":"Điểm nhấn","value":"Depot Metro 4 (quy hoạch) + Picity High Park"},{"key":"Đất nền Thạnh Xuân (cũ)","value":"44–60 tr/m² (nguồn khác: 20–30 tr/m²)"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685) — riêng dải giá đất nền có độ vênh lớn giữa các nguồn rao. Phường hợp nhất Thới An + Thạnh Xuân — tâm điểm phía Bắc Quận 12 với quy hoạch depot Metro 4 và compound Picity High Park. Độ vênh giá đất nền giữa các nguồn (20–30 vs 44–60 tr/m²) phản ánh chênh lệch lớn giữa hẻm sâu và mặt tiền trục chính — phải định giá theo từng vị trí cụ thể.',26),
  ('3a96c2f5-0508-5747-a8dc-c782da1cedc0','00000000-0000-0000-0000-00000000b001','p-an-phu-dong','P. An Phú Đông (mới)','location',null,'[{"key":"Sáp nhập từ","value":"An Phú Đông + Thạnh Lộc"},{"key":"Trụ sở","value":"540 Hà Huy Giáp"},{"key":"Đặc điểm","value":"Toàn bộ mặt sông Sài Gòn phía Đông Q12"},{"key":"Đất nền","value":"An Phú Đông 30–45 · Thạnh Lộc 55–80 tr/m²"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685; giá: tổng hợp nguồn rao bán) Phường ven sông của Quận 12 — quỹ đất nhà vườn, nhà phố ven sông và các dự án đất nền (Senturia Vườn Lài, An Phú Đông Riverside). Thạnh Lộc cũ có dải giá cao nhất Q12 nhờ vị trí giáp Gò Vấp + ven sông.',27),
  ('36377d0c-744b-5400-b8b9-e0034249c606','00000000-0000-0000-0000-00000000b001','p-dong-hung-thuan','P. Đông Hưng Thuận (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Tân Thới Nhất + Tân Hưng Thuận + Đông Hưng Thuận"},{"key":"Quy mô","value":"8,26 km² — 182.895 dân"},{"key":"Vị trí","value":"Cửa ngõ giáp Tân Bình/Gò Vấp, nút An Sương"},{"key":"Đất nền","value":"Tân Thới Nhất 50–70 · Tân Hưng Thuận 35–44 · ĐHT 33–40 tr/m²"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685) Phường đông dân nhất Quận 12, sát nút An Sương — điểm đầu trục QL22 mở rộng đi Vinhomes Saigon Park. Mặt bằng giá cao nhất nhì Q12 nhờ gần trung tâm và hạ tầng hiện hữu dày.',28),
  ('7766bb29-1b2a-5246-898e-7d4fa5272707','00000000-0000-0000-0000-00000000b001','p-trung-my-tay','P. Trung Mỹ Tây (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Trung Mỹ Tây + Tân Chánh Hiệp"},{"key":"Điểm nhấn","value":"Gần QTSC + Depot Tham Lương (Metro 2)"},{"key":"Đất nền Tân Chánh Hiệp (cũ)","value":"17–25 tr/m² — thấp nhất Q12"}]'::jsonb,'"Tân Chánh Hiệp 17–25 triệu/m² nằm cách depot Metro 2 vài phút xe — đây là khoảng giá mà khu Đông không còn tồn tại từ lâu."','✅ ĐÃ XÁC MINH (NQ 1685) Vùng giá thấp nhất Quận 12 nhưng lại ôm 2 tài sản hạ tầng: Công viên phần mềm Quang Trung và Depot Tham Lương. Chênh lệch "giá thấp nhất + catalyst mạnh" khiến đây là khu đáng theo dõi nhất cho nhà đầu tư đất nền ngân sách nhỏ.',29),
  ('1b3f6d49-63ce-5a7c-af1f-9272131e2a00','00000000-0000-0000-0000-00000000b001','p-tan-thoi-hiep','P. Tân Thới Hiệp (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Hiệp Thành + Tân Thới Hiệp"},{"key":"Đất nền","value":"Hiệp Thành 23–34 · Tân Thới Hiệp 25–33 tr/m²"},{"key":"Đặc điểm","value":"Khu dân cư hiện hữu, nhiều dự án đất nền cũ (Hiệp Thành City…)"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685) Vùng lõi dân cư phía Bắc với mặt bằng giá trung bình thấp, phù hợp tệp mua ở thực ngân sách 3–5 tỷ cho nhà phố hẻm xe hơi.',30),
  ('ba19fe43-14a0-59cf-b4ee-c0336263eaf8','00000000-0000-0000-0000-00000000b001','xuan-thoi-son','Xuân Thới Sơn (Hóc Môn cũ)','location',null,'[{"key":"Vai trò","value":"Xã đặt dự án Vinhomes Saigon Park"},{"key":"Ranh giới","value":"Giáp QL22, Vành đai 3, kênh An Hạ, kênh Xáng"},{"key":"Quan hệ với Q12","value":"Giáp ranh phía Tây Bắc Quận 12"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Địa bàn thực tế của Vinhomes Saigon Park. Đất quanh dự án thuộc Hóc Môn cũ — nhà đầu tư cần phân biệt rõ "đất Quận 12 hưởng lợi gián tiếp" với "đất Hóc Môn sát dự án" vì hai vùng có mặt bằng giá và pháp lý nền khác nhau.',31),
  ('05a233a2-bf45-5305-a906-ecf3110afa54','00000000-0000-0000-0000-00000000b001','tay-bac','Khu Tây Bắc TP.HCM','location',null,'[{"key":"Phạm vi","value":"Quận 12 + Hóc Môn + Củ Chi (cũ)"},{"key":"Nguồn cung căn hộ","value":"~28 dự án đã bàn giao, ~15.500 căn (đa số trước 2020)"},{"key":"Định vị","value":"Vùng trũng giá — tương đồng Dĩ An/Thuận An giai đoạn trước (Biggee)"},{"key":"Chiến lược TP","value":"Hướng giãn dân + phát triển đô thị vệ tinh"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (báo cáo Biggee) Khu Tây Bắc là hướng phát triển còn "nguyên bản" nhất của TP.HCM: nguồn cung mới gần như đóng băng từ 2020, trong khi 2026 dồn dập 4 catalyst (VĐ3, Metro 2, QL22, Vinhomes). Cấu trúc này từng xuất hiện ở khu Đông 2018–2020 trước chu kỳ tăng giá mạnh.',32),
  ('06b9a6c0-a894-50f0-872e-0ecee69c8aa2','00000000-0000-0000-0000-00000000b001','picity-hp','Picity High Park','comparable','Đối thủ trực tiếp gần nhất tại Q12','[{"key":"CĐT","value":"Pi Group (pháp nhân: Gia Cư)"},{"key":"Vị trí","value":"Thạnh Xuân 13, P. Thới An (mới)"},{"key":"Quy mô","value":"8,6 ha — 2.446 căn hộ + 135 shophouse + 36 nhà phố"},{"key":"Thiết kế","value":"6 block 15–18 tầng, mật độ XD 23%"},{"key":"Bàn giao","value":"2021–2022 — sổ hồng lâu dài"},{"key":"Giá thứ cấp","value":"38–53 tr/m² (2PN ~2,49–3,22 tỷ)"}]'::jsonb,'"Muốn biết căn hộ Vinhomes khu này sẽ neo giá thế nào, nhìn Picity: 38–53 triệu/m² cho compound đã có sổ. Vinhomes mở bán cao hơn mức này bao nhiêu — đó là phần khách trả cho thương hiệu và kỳ vọng."','✅ ĐÃ XÁC MINH Compound "chuẩn resort" duy nhất đã vận hành tại Quận 12 — benchmark trực tiếp cho mọi sản phẩm cao tầng mới của khu vực, kể cả căn hộ Vinhomes Saigon Park sau này. Pháp lý sạch (đã có sổ), thanh khoản thứ cấp tốt nhất Q12.',33),
  ('c0a0d334-cb4e-51cd-b3b2-e2f296b45dca','00000000-0000-0000-0000-00000000b001','picity-sky','Picity Sky Park (Dĩ An)','comparable',null,'[{"key":"Vị trí","value":"P. An Bình, Dĩ An (Bình Dương cũ)"},{"key":"Quy mô","value":"1.568 căn"},{"key":"Bàn giao","value":"Q4/2026 – Q1/2027"},{"key":"Giá","value":"~40–60 tr/m²"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Dự án cùng hệ Pi Group ở cửa ngõ Đông Bắc — tham chiếu cho thấy căn hộ vùng giáp ranh TP.HCM (cũ) đã thiết lập mặt bằng 40–60 tr/m², cao hơn trung bình Quận 12 hiện tại.',34),
  ('932a1dac-f40e-5123-8c7d-835f8174e01b','00000000-0000-0000-0000-00000000b001','hado-q12','Hà Đô Thới An / Green Lane','comparable',null,'[{"key":"CĐT","value":"Tập đoàn Hà Đô"},{"key":"Vị trí","value":"Khu Thới An, Quận 12"},{"key":"Vai trò","value":"Nguồn cung căn hộ – nhà phố hiện hữu"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (mức độ chi tiết hạn chế trong dữ liệu thu thập) Cụm dự án Hà Đô tại Thới An thuộc nhóm nguồn cung hiện hữu cạnh tranh phân khúc trung cấp với Picity và các sản phẩm thứ cấp khu Bắc Q12.',35),
  ('ac94906c-0d3f-5819-99b8-27fed95769f9','00000000-0000-0000-0000-00000000b001','canho-cu-q12','Căn hộ Q12 thế hệ cũ','comparable',null,'[{"key":"Đại diện","value":"Prosper Plaza, Tecco Green Nest, Stown Tham Lương, Topaz Home"},{"key":"Đặc điểm","value":"Bàn giao trước 2020 — phân khúc bình dân"},{"key":"Vai trò","value":"Sàn giá thấp của thị trường căn hộ Q12"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Lớp căn hộ bình dân bàn giao trước 2020 tạo "sàn giá" cho thị trường (vùng 30–38 tr/m²). Khoảng cách giữa lớp này và Picity (38–53) là thước đo premium mà thị trường Q12 chấp nhận trả cho chất lượng compound.',36),
  ('cb0bc67d-9cd7-5958-a5f5-a4c6caa308ed','00000000-0000-0000-0000-00000000b001','cityland-gv','Cityland Gò Vấp','comparable',null,'[{"key":"Dự án","value":"Cityland Park Hills / Garden Hills"},{"key":"Vị trí","value":"Gò Vấp — giáp ranh phía Nam Q12"},{"key":"Vai trò","value":"Benchmark trần giá nhà phố compound vùng lân cận"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Nhà phố compound Cityland tại Gò Vấp neo mặt bằng giá cao hơn Quận 12 đáng kể — tham chiếu "trần giá lân cận" để định vị nhà phố Q12 và đối chiếu với giá rumor của Vinhomes Saigon Park.',37),
  ('a4b96b57-ab43-5f2c-8646-391805d255d5','00000000-0000-0000-0000-00000000b001','datnen-duan-q12','Đất nền/nhà phố dự án Q12','comparable',null,'[{"key":"Đại diện","value":"Senturia Vườn Lài, An Phú Đông Riverside, Phú Long Riverside, Thới An City, Hiệp Thành City"},{"key":"Phân bố","value":"Chủ yếu ven sông (An Phú Đông) và Bắc Q12"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Lớp dự án đất nền/nhà phố có pháp lý dự án — thanh khoản và giá ổn định hơn đất nền tự do, là lựa chọn "phòng thủ" cho nhà đầu tư muốn đón sóng Vinhomes nhưng cần sổ từng nền.',38),
  ('595d7a05-60c5-5c07-94ca-35178e3ec66a','00000000-0000-0000-0000-00000000b001','happy-one-hm','Happy One (Hóc Môn)','comparable',null,'[{"key":"CĐT","value":"Vạn Xuân Group"},{"key":"Vị trí","value":"Hóc Môn cũ — trục QL22"},{"key":"Vai trò","value":"Nguồn cung căn hộ hiếm hoi sát trục QL22"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (mức độ chi tiết hạn chế trong dữ liệu thu thập) Đại diện nguồn cung căn hộ phía Hóc Môn trên trục QL22 — cùng hành lang hưởng lợi với Vinhomes Saigon Park, dùng làm tham chiếu giá "vùng dự án" so với "vùng Q12".',39),
  ('057acc3c-e70f-5e5c-95b9-8f82f44ba76f','00000000-0000-0000-0000-00000000b001','gia-canho','Mặt bằng giá căn hộ Q12','market',null,'[{"key":"Trung bình","value":"~38 tr/m² (cao nhất ~60 tr/m²)"},{"key":"Giá trị giao dịch phổ biến","value":"1,99–4,45 tỷ/căn (TB ~2,75 tỷ)"},{"key":"Nguồn cung mới","value":"Đóng băng — mới nhất Picity bàn giao 2022"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (tổng hợp Batdongsan, Homedy, Biggee) Căn hộ Quận 12 đang ở vùng 38 tr/m² trung bình — thấp hơn rõ rệt khu Đông/Nam và cả Dĩ An/Thuận An (40–70). Kết hợp nguồn cung mới khan hiếm 4 năm liền, mọi dự án mở bán mới (đặc biệt mang thương hiệu Vinhomes) sẽ tự động re-rate mặt bằng.',40),
  ('6cc5731f-112a-5fd7-a90f-af9555e6eeb5','00000000-0000-0000-0000-00000000b001','gia-datnen','Giá đất nền theo phường (cũ)','market',null,'[{"key":"Tân Thới Nhất","value":"50–70 tr/m²"},{"key":"Thạnh Lộc","value":"55–80 tr/m²"},{"key":"Thạnh Xuân","value":"44–60 (nguồn khác 20–30) tr/m²"},{"key":"Tân Hưng Thuận","value":"35–44 tr/m²"},{"key":"An Phú Đông","value":"30–45 tr/m²"},{"key":"Đông Hưng Thuận","value":"33–40 tr/m²"},{"key":"Hiệp Thành / Tân Thới Hiệp","value":"23–34 / 25–33 tr/m²"},{"key":"Tân Chánh Hiệp","value":"17–25 tr/m²"},{"key":"Nhà phố","value":"~40–134 tr/m² tùy vị trí"}]'::jsonb,null,'✅ ĐÃ XÁC MINH là giá RAO (tổng hợp Batdongsan, Homedy, Nhà Tốt) — giá giao dịch thực có thể thấp hơn 5–15%. Biên độ giá trong Q12 rất rộng (17 → 80 tr/m²): trục ven sông + giáp Gò Vấp cao nhất, vùng lõi phía Bắc thấp nhất. Đây là thị trường định giá theo vi mô vị trí, không theo "giá Quận 12" chung chung.',41),
  ('877d758c-e29a-53a9-811d-d9fa8d4aa368','00000000-0000-0000-0000-00000000b001','bien-dong-gia','Biến động giá 2025–2026','market',null,'[{"key":"Nhà đất Q12 (Nhà Tốt, T5/2026)","value":"+0,4% MoM · +8,5% YoY"},{"key":"Căn hộ (một số nguồn khác)","value":"~+15,5% YoY — cần đối chiếu thêm"},{"key":"Chênh rao vs giao dịch","value":"Giá rao thường cao hơn thực 5–15%"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — hai nguồn cho hai con số tăng trưởng khác nhau (+8,5% nhà đất chung vs ~+15,5% riêng căn hộ), chưa có dữ liệu giao dịch chuẩn CBRE/Savills để chốt. Tín hiệu chung: giá Q12 đã bắt đầu phản ánh kỳ vọng Metro 2 + Vinhomes, nhưng chưa sốt nóng — mức tăng một chữ số là vùng còn vào được, khác giai đoạn sốt đất 2021–2022.',42),
  ('bddb55f0-223e-5fec-9d3f-950f81484108','00000000-0000-0000-0000-00000000b001','cho-thue','Tỷ suất cho thuê','market',null,'[{"key":"Gross yield căn hộ","value":"~3,5–4,5%/năm"},{"key":"Ví dụ","value":"2PN 58m² giá ~2,49 tỷ → thuê ~9 tr/tháng (~4,3%)"},{"key":"Giá thuê phổ biến","value":"2PN: 6,5–10 tr · 3PN: 8–13 tr/tháng"},{"key":"⚠ Nguồn","value":"Ước tính từ rao vặt — chưa trừ phí QL, thuế, trống phòng"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN (ước tính từ nhatot.com, canho.com.vn, thuecanho123.com — KHÔNG phải số liệu CBRE/Savills) Yield ~4% gross đủ bù một phần lãi vay cho người mua ở thực/cho thuê, được chống lưng bởi cầu thuê từ QTSC và cụm KCN. Net yield thực tế sau phí khoảng 3–3,5%.',43),
  ('8bb66f8a-ddf2-5841-a0ba-316389c5c3c3','00000000-0000-0000-0000-00000000b001','rui-ro','Bản đồ rủi ro','market','⚠ Đọc kỹ trước khi tư vấn xuống tiền','[{"key":"1. Giá rumor cao","value":"Nhà phố VSP đồn 80–120 tr/m² — chưa có căn cứ"},{"key":"2. Hạ tầng trễ hẹn","value":"Metro 2 từng trễ ~14 năm; VĐ3 có thể lùi cuối 2026"},{"key":"3. Chưa có giá chính thức","value":"VSP chưa công bố giá/CSBH"},{"key":"4. Địa chất","value":"Ven sông nền đất yếu, ngập cục bộ"},{"key":"5. Giá chạy trước tin","value":"Đất nền có thể đã phản ánh kỳ vọng"}]'::jsonb,'"Tư vấn trung thực là lợi thế cạnh tranh: nói rõ với khách Metro 2 từng trễ 14 năm. Khách mất niềm tin vì môi giới giấu rủi ro, không phải vì rủi ro tồn tại."','✅ ĐÃ XÁC MINH về mặt dữ kiện nền (lịch sử trễ tiến độ, cảnh báo Ban Giao thông) — mức độ ảnh hưởng là đánh giá. Rủi ro lớn nhất không phải dự án "ảo" (pháp lý VSP rất thật) mà là trả giá tương lai cho tài sản hiện tại: mua đất nền theo giá đã cộng kỳ vọng, trong khi catalyst có thể trễ 1–2 năm.',44),
  ('6e9cf50f-222d-5e59-aba1-4a5f789dc355','00000000-0000-0000-0000-00000000b001','khuyen-nghi','Khuyến nghị & mốc theo dõi','market',null,'[{"key":"Ưu tiên hiện tại","value":"Sản phẩm pháp lý hoàn chỉnh đã có sổ"},{"key":"Mốc 1","value":"VSP công bố bảng giá & CSBH chính thức GĐ1"},{"key":"Mốc 2","value":"VĐ3 thông xe thật (theo dõi 30/6/2026 → có thể lùi)"},{"key":"Mốc 3","value":"Metro 2 đạt tiến độ xây lắp >30%"},{"key":"Tín hiệu đứng ngoài","value":"Rumor nhà phố >100 tr/m² + hạ tầng lùi"}]'::jsonb,'"Bán bằng mốc, không bán bằng cảm xúc: ''Anh/Chị chưa cần quyết hôm nay — nhưng khi Vinhomes ra bảng giá chính thức, cả khu này sẽ định giá lại trong 2 tuần. Em sẽ báo Anh/Chị đúng ngày đó.''"','Khung hành động (T6/2026): Nhà đầu tư — ưu tiên đất nền có sổ Thạnh Xuân/Thới An, căn hộ Picity thứ cấp; tránh "cọc giữ chỗ" VSP khi chưa có HĐMB. Người ở thực — Picity (ở ngay, có sổ) hoặc căn hộ 2PN 2,3–3 tỷ; yield ~4% bù một phần lãi vay. Đánh giá lại toàn bộ khi 1 trong 3 mốc bên cạnh xảy ra.',45),
  ('7b2d1b3c-025b-570d-b033-49e83b7e3657','00000000-0000-0000-0000-00000000b001','nq-1685','NQ 1685 — sáp nhập phường','policy',null,'[{"key":"Văn bản","value":"NQ 1685/NQ-UBTVQH15 ngày 16/6/2025"},{"key":"Hiệu lực","value":"1/7/2025"},{"key":"Kết quả","value":"Quận 12: 11 phường → 5 phường"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (Thư Viện Pháp Luật) 5 phường mới: Đông Hưng Thuận, Trung Mỹ Tây, Tân Thới Hiệp, Thới An, An Phú Đông. Hệ quả thực tế cho giao dịch: địa chỉ trên sổ/hợp đồng theo tên phường cũ vẫn hợp lệ nhưng giấy tờ mới phải ghi tên phường mới — môi giới cần thuộc bảng mapping để tránh nhầm thửa.',46),
  ('f53f2096-bc3b-5e77-b3d5-e76916a03ed6','00000000-0000-0000-0000-00000000b001','nq-202','NQ 202 — TP.HCM mới','policy',null,'[{"key":"Nội dung","value":"Sáp nhập TP.HCM + Bình Dương + Bà Rịa–Vũng Tàu"},{"key":"Hiệu lực","value":"1/7/2025"},{"key":"Thay đổi lớn","value":"Bãi bỏ cấp quận/huyện — phường trực thuộc TP"}]'::jsonb,'"Một câu thay đổi cuộc chơi với khách tỉnh: bây giờ mua Quận 12 hay mua Dĩ An đều là hộ khẩu TP.HCM — thứ khác nhau duy nhất còn lại là giá và hạ tầng."','✅ ĐÃ XÁC MINH "Quận 12" từ 1/7/2025 chỉ còn là tên gọi khu vực. Đồng thời, Dĩ An/Thuận An (Bình Dương cũ) nay cùng một đơn vị hành chính TP.HCM — ranh giới tâm lý "mua Bình Dương hay mua TP.HCM" đã biến mất, khiến so sánh giá Q12 vs Dĩ An trở thành so sánh nội thành phố.',47);
